import{_ as t,o as l,c as r,a2 as n}from"./chunks/framework.DnrXFDHb.js";const C=JSON.parse('{"title":"MLCC 深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/被動元件研究/MLCC深度研究.md","filePath":"Deep32Q知識庫/產業洞察/被動元件研究/MLCC深度研究.md"}'),e={name:"Deep32Q知識庫/產業洞察/被動元件研究/MLCC深度研究.md"};function i(s,a,o,d,h,c){return l(),r("div",null,[...a[0]||(a[0]=[n(`<h1 id="mlcc-深度研究" tabindex="-1">MLCC 深度研究 <a class="header-anchor" href="#mlcc-深度研究" aria-label="Permalink to &quot;MLCC 深度研究&quot;">​</a></h1><p><strong>更新日期：2026-05-12</strong><strong>產出者：Dr.32 知識管家（subagent）</strong></p><hr><h2 id="_1-mlcc-技術原理與結構" tabindex="-1">1. MLCC 技術原理與結構 <a class="header-anchor" href="#_1-mlcc-技術原理與結構" aria-label="Permalink to &quot;1. MLCC 技術原理與結構&quot;">​</a></h2><p>MLCC（Multilayer Ceramic Capacitor，積層陶瓷電容）是最廣泛使用的被動元件。</p><h3 id="基本結構" tabindex="-1">基本結構 <a class="header-anchor" href="#基本結構" aria-label="Permalink to &quot;基本結構&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────┐</span></span>
<span class="line"><span>│  外部電極（端電極）   │ ← 焊接至 PCB</span></span>
<span class="line"><span>├─────────────────────┤</span></span>
<span class="line"><span>│ 陶瓷介電層 (BaTiO₃) │ ← 儲存電荷</span></span>
<span class="line"><span>│ 內部電極（金屬層）   │ ← Ni/Cu/AgPd</span></span>
<span class="line"><span>├─────────────────────│ 重複疊層 100-3,000 層</span></span>
<span class="line"><span>│ 陶瓷介電層          │</span></span>
<span class="line"><span>├─────────────────────┤</span></span>
<span class="line"><span>│ 內部/外部電極       │ ← 焊接至 PCB</span></span>
<span class="line"><span>└─────────────────────┘</span></span></code></pre></div><h3 id="關鍵參數" tabindex="-1">關鍵參數 <a class="header-anchor" href="#關鍵參數" aria-label="Permalink to &quot;關鍵參數&quot;">​</a></h3><ul><li><strong>容值</strong>：pF → μF 級別</li><li><strong>電壓等級</strong>：6.3V、16V、50V、100V、200V、&gt;1kV（HVDC）</li><li><strong>尺寸</strong>：1005 (402)、0603、0402、0201、01005</li><li><strong>介電材質</strong>：X7R（通用）、X5R、C0G/NP0（高頻低損耗）</li></ul><hr><h2 id="_2-全球市佔分布" tabindex="-1">2. 全球市佔分布 <a class="header-anchor" href="#_2-全球市佔分布" aria-label="Permalink to &quot;2. 全球市佔分布&quot;">​</a></h2><h3 id="主要廠商市佔率-2025-2026" tabindex="-1">主要廠商市佔率（2025-2026） <a class="header-anchor" href="#主要廠商市佔率-2025-2026" aria-label="Permalink to &quot;主要廠商市佔率（2025-2026）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>排名</th><th>廠商</th><th>國家</th><th>MLCC 市佔率</th><th>備註</th></tr></thead><tbody><tr><td>1</td><td><strong>村田製作所</strong> (Murata)</td><td>🇯🇵 日本</td><td>~28-30%</td><td>全球最大，AI 伺服器高階 MLCC 領先</td></tr><tr><td>2</td><td><strong>三星電機</strong> (SEM)</td><td>🇰🇷 韓國</td><td>~22-24%</td><td>高容值 MLCC 技術領先，稼動率 &gt;90%</td></tr><tr><td>3</td><td><strong>國巨</strong> (Yageo/KEMET)</td><td>🇹🇼 台灣</td><td>~7-9%</td><td>全球前三，鉭電 + MLCC + 電阻整合</td></tr><tr><td>4</td><td><strong>太陽誘電</strong> (TDK)</td><td>🇯🇵 日本</td><td>~8-10%</td><td>車用 MLCC 強項，TLVR 電感</td></tr><tr><td>5</td><td><strong>華新科</strong> (Walsin)</td><td>🇹🇼 台灣</td><td>~5-7%</td><td>銅電極技術領先，AI 伺服器 MLCC 供應商</td></tr></tbody></table><h3 id="其他台廠" tabindex="-1">其他台廠 <a class="header-anchor" href="#其他台廠" aria-label="Permalink to &quot;其他台廠&quot;">​</a></h3><ul><li><strong>禾伸堂</strong> (Holy Stone, 3026)：高壓 MLCC，已打入 NVIDIA A100/H100/Blackwell/Vera Rubin 供應鏈</li><li><strong>國巨集團</strong>：透過 KEMET 收購整合鉭電容（全球 &gt;40% 市佔）</li></ul><hr><h2 id="_3-技術趨勢" tabindex="-1">3. 技術趨勢 <a class="header-anchor" href="#_3-技術趨勢" aria-label="Permalink to &quot;3. 技術趨勢&quot;">​</a></h2><h3 id="_1-小型化" tabindex="-1">（1）小型化 <a class="header-anchor" href="#_1-小型化" aria-label="Permalink to &quot;（1）小型化&quot;">​</a></h3><ul><li><strong>尺寸演進</strong>：1005 (4.0×2.0mm) → 0603 → 0402 → 0201 → <strong>01005</strong> (0.4×0.2mm)</li><li>01005 尺寸已量產，用於手機、可穿戴裝置</li></ul><h3 id="_2-高容值" tabindex="-1">（2）高容值 <a class="header-anchor" href="#_2-高容值" aria-label="Permalink to &quot;（2）高容值&quot;">​</a></h3><ul><li>單顆 MLCC 容值突破 <strong>100μF</strong>（原為 μF 級）</li><li>AI 伺服器需要大容量、低 ESR 的 MLCC</li></ul><h3 id="_3-高電壓-hvdc-架構" tabindex="-1">（3）高電壓（HVDC 架構） <a class="header-anchor" href="#_3-高電壓-hvdc-架構" aria-label="Permalink to &quot;（3）高電壓（HVDC 架構）&quot;">​</a></h3><ul><li><strong>&gt;1kV MLCC</strong>：800V HVDC 架構推升需求</li><li>AI 伺服器電源架構從 48V 轉向 400V+，高壓 MLCC 用量大增</li><li>禾伸堂已供應 NVIDIA Blackwell 平台高壓 MLCC</li></ul><h3 id="_4-高耐溫" tabindex="-1">（4）高耐溫 <a class="header-anchor" href="#_4-高耐溫" aria-label="Permalink to &quot;（4）高耐溫&quot;">​</a></h3><ul><li>AI 伺服器內部溫度可達 85°C+，需要高耐溫 MLCC</li><li>X7R、X5S 材質持續優化</li></ul><h3 id="_5-銅電極技術-華新科主導" tabindex="-1">（5）銅電極技術（華新科主導） <a class="header-anchor" href="#_5-銅電極技術-華新科主導" aria-label="Permalink to &quot;（5）銅電極技術（華新科主導）&quot;">​</a></h3><ul><li>傳統：AgPd 內電極 → 成本高</li><li><strong>銅電極</strong>：華新科領先，成本降低 30-50%</li><li>銅電極 MLCC 已量產，2026 年持續擴充</li></ul><hr><h2 id="_4-ai-驅動的-mlcc-需求爆發" tabindex="-1">4. AI 驅動的 MLCC 需求爆發 <a class="header-anchor" href="#_4-ai-驅動的-mlcc-需求爆發" aria-label="Permalink to &quot;4. AI 驅動的 MLCC 需求爆發&quot;">​</a></h2><h3 id="gb200-nvl72-案例" tabindex="-1">GB200 NVL72 案例 <a class="header-anchor" href="#gb200-nvl72-案例" aria-label="Permalink to &quot;GB200 NVL72 案例&quot;">​</a></h3><ul><li><strong>單機櫃 MLCC 需求</strong>：約 <strong>441,000 顆</strong></li><li>是傳統 AI 伺服器的 <strong>10-21 倍</strong></li><li>是手機的約 <strong>30 倍</strong></li></ul><h3 id="需求預測" tabindex="-1">需求預測 <a class="header-anchor" href="#需求預測" aria-label="Permalink to &quot;需求預測&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年份</th><th>AI 伺服器 MLCC 需求量</th><th>備註</th></tr></thead><tbody><tr><td>2025</td><td>~726 億顆</td><td>GB200 開始量產</td></tr><tr><td>2026</td><td>~726 億顆（持續成長）</td><td>Blackwell 全面量產</td></tr><tr><td>2027</td><td>~1,367 億顆</td><td>Vera Rubin 平台放量</td></tr></tbody></table><h3 id="供需分析" tabindex="-1">供需分析 <a class="header-anchor" href="#供需分析" aria-label="Permalink to &quot;供需分析&quot;">​</a></h3><ul><li><strong>村田/三星電機稼動率</strong>：&gt;90%（滿載）</li><li><strong>高階 MLCC 漲價</strong>：15-35%（2025-2026 年）</li><li><strong>交期延長</strong>：部分高階規格交期達 16-20 週</li><li><strong>庫存水位</strong>：中國經銷商健康補貨，整體庫存正常</li></ul><hr><h2 id="_5-台廠-mlcc-競爭力分析" tabindex="-1">5. 台廠 MLCC 競爭力分析 <a class="header-anchor" href="#_5-台廠-mlcc-競爭力分析" aria-label="Permalink to &quot;5. 台廠 MLCC 競爭力分析&quot;">​</a></h2><h3 id="國巨-yageo" tabindex="-1">國巨 (Yageo) <a class="header-anchor" href="#國巨-yageo" aria-label="Permalink to &quot;國巨 (Yageo)&quot;">​</a></h3><ul><li>全球前三，透過 KEMET 整合鉭電容優勢</li><li>AI 相關營收佔比：Q4 2025 ~12% → Q1 2026 13-14% → 年底目標 &gt;15%</li><li>訂單能見度延伸至 2026 H2</li></ul><h3 id="華新科-walsin" tabindex="-1">華新科 (Walsin) <a class="header-anchor" href="#華新科-walsin" aria-label="Permalink to &quot;華新科 (Walsin)&quot;">​</a></h3><ul><li>全球前五，MLCC 佔營收 ~60%</li><li><strong>銅電極技術</strong>：成本優勢，取代貴金屬內電極</li><li>AI 營收佔比：2025 &gt;10% → 2026 預估翻倍</li><li>X6S 型、中高壓 MLCC 供應 AI 伺服器</li></ul><h3 id="禾伸堂-holy-stone" tabindex="-1">禾伸堂 (Holy Stone) <a class="header-anchor" href="#禾伸堂-holy-stone" aria-label="Permalink to &quot;禾伸堂 (Holy Stone)&quot;">​</a></h3><ul><li>高壓/低損耗 NP0 MLCC 專家</li><li>已打入 NVIDIA A100 → H100 → Blackwell → Vera Rubin 全世代</li><li>AI 相關佔 MLCC 業務 ~18-20%（2025），2026 預估翻倍</li><li>AI 產線稼動率 &gt;100%，2026-2029 資本支出 ~NT$30 億擴產</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>Mordor Intelligence</strong> (2026-05): MLCC Market Report</li><li><strong>Grand View Research</strong> (2026-05): MLCC Market Analysis</li><li><strong>TrendForce</strong> (2025-12): 村田 AI 伺服器電源模組量產</li><li><strong>Digitimes</strong> (2026-03): 國巨鉭電漲價、禾伸堂產能</li><li><strong>StatementDog / StockAnalysis</strong>: 國巨 2025-2026 財務</li><li><strong>Fugle / Cmoney</strong>: 華新科、禾伸堂法說會</li><li><strong>Passive-Components.eu</strong>: MLCC 廠商漲價新聞</li><li><strong>Samsung Electro-Mechanics</strong> (2026): 高容值 MLCC 產品新聞</li><li><strong>7setronic</strong> (2026): AI MLCC 市場需求分析</li><li><strong>IntelMarketResearch</strong> (2026): MLCC for AI Server/Automotive Market</li></ol>`,46)])])}const u=t(e,[["render",i]]);export{C as __pageData,u as default};
